#include <stdio.h>

int binarySearch(int arr[], int low, int high, int key) {
    while(low <= high) {
        int mid = low + (high - low) / 2;
        if(arr[mid] == key) return mid;
        if(arr[mid] < key) low = mid + 1;
        else high = mid - 1;
    }
    return -1;
}

