            a[i][j] = a[i][k];
            a[i][k] = temp;
        }
    }
    printf("Rotated matrix:\n");
    for(int i = 0; i < n; i++) {
        for(int j = 0; j < n; j++)
            printf("%d ", a[i][j]);
        printf("\n");
    }
    return 0;
}

